ritual_block_verification::verify_short_async_block_with_simulators(
    block, parent_state,
    |commitment| {
        let evm_env = evm_config.evm_env(parent_header.header())?;
        let mut evm = evm_config.evm_with_env_and_inspector(StateProviderDatabase::new(parent_state), evm_env, inspector.clone());
        evm.transact(recovered_original)?;
        Ok(SimulatedAsyncCall { async_call_count: inspector.async_call_count(), precompile_address: detected.precompile_address, input: detected.input })
    }, ...
)

let job_active = ritual_async_registry::job_exists_and_active(&mut db, None, commitment.origin_tx, current_block)?;
if job_active { return Err(BlockVerificationError::InvalidAsyncCommitment(...)); }
verify_wallet_for_commitment(&mut db, original_payer, commitment.precompile_address, &commitment.precompile_input, commitment.ttl, current_block)?;
let simulated = simulate_commitment(commitment)?;
if simulated.async_call_count != 1 || simulated.precompile_address != commitment.precompile_address || simulated.input != commitment.precompile_input { return Err(BlockVerificationError::InvalidAsyncCommitment(...)); }
